mapper.update:
update auction_settlement_log
set winner_funds_settled = true,
    updated_at = #{updatedAt}
where room_id = #{roomId}

update auction_settlement_log
set deposits_released = true,
    updated_at = #{updatedAt}
where room_id = #{roomId}

update auction_settlement_log
set status = 'SUCCESS',
    last_error = null,
    updated_at = #{updatedAt},
    settled_at = #{settledAt}
where room_id = #{roomId}

update auction_settlement_log
set status = 'FAILED',
    last_error = #{lastError},
    updated_at = #{updatedAt}
where room_id = #{roomId}
